#include <stdlib.h>

int countPartitions(int* a, int n, int maxSum) {
    int partitions = 1;
    long long subarraySum = 0;
    for (int i = 0; i < n; i++) {
        if (subarraySum + a[i] <= maxSum) {
            subarraySum += a[i];
        } else {
            partitions++;
            subarraySum = a[i];
        }
    }
    return partitions;
}

int largestSubarraySumMinimized(int* a, int n, int k) {
    int low = a[0];
    int high = 0;
    for (int i = 0; i < n; i++) {
        low = (low > a[i]) ? a[i] : low;
        high += a[i];
    }
    while (low < high) {
        int mid = low + (high - low) / 2;
        if (countPartitions(a, n, mid) <= k) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}

