    countPartitions(a, maxSum) {
        let partitions = 1; // at least one partition
        let subarraySum = 0; // current subarray sum

        for (let num of a) {
            // Add to current subarray if it doesn't exceed maxSum
            if (subarraySum + num <= maxSum) {
                subarraySum += num;
            } else {
                // Start a new subarray
                partitions++;
                subarraySum = num;
            }
        }
        return partitions;
    }

    // Finds smallest possible largest subarray sum for exactly k partitions
    largestSubarraySumMinimized(a, k) {
        let low = Math.max(...a); // max element
        let high = a.reduce((acc, val) => acc + val, 0); // sum of array

        // Brute-force from low to high
        while (low < high) {
            let mid = low + Math.floor((high - low) / 2);
            if (this.countPartitions(a, mid) <= k) {
                high = mid;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }
}

